SELECT SUM(interest) AS total_interest_paid
FROM transactions
WHERE loan_id = 1;

SELECT COUNT(*) AS total_transactions
FROM transactions
WHERE loan_id = 1;

SELECT SUM(interest) AS total_accrued_interest
FROM transactions
WHERE office_id = 1 AND transaction_type = 'Accrual';

SELECT SUM(amount) AS total_loan_amount
FROM loan_accounts
WHERE total_fees_paid > total_penalties_paid;

SELECT SUM(t.principal) AS total_principal_paid
FROM transactions t
WHERE t.transaction_type = 'Repayment' AND t.principal > 0;

SELECT entry_id, transaction_date
FROM transactions
ORDER BY transaction_date DESC;

SELECT COUNT(office_id) AS office_count
FROM offices
WHERE location = 'New York City';

SELECT transaction_date, amount
FROM transactions
ORDER BY transaction_date DESC;
